external_knowledge:
- Active size charts imply currently applicable or in-use charts; 
- Target gender 'Female' refers to size charts specifically designed for females;
- Measurement systems (e.g., 'CM', 'IN') are units of measurement for size (e.g., body size, clothing size);
- Created_at refers to the timestamp when the size chart was created or added to the database.

sql:
SELECT size, COUNT(*) 
FROM size_details 
GROUP BY size;

SELECT AVG(chart_count) AS avg_charts_per_brand
FROM (
  SELECT brand_id, COUNT(*) AS chart_count
  FROM size_chart
  GROUP BY brand_id
);

SELECT
  sc.chart_id,
  sc.chart_name,
  AVG(
    CAST(
      sd.bust_cm AS REAL
    ) + CAST(
      sd.waist_cm AS REAL
    ) + CAST(
      sd.hips_cm AS REAL
    ) + CAST(
      sd.shoulder_cm AS REAL
    ) + CAST(
      sd.sleeve_length_cm AS REAL
    ) + CAST(
      sd.rise_cm AS REAL
    ) + CAST(
      sd.inseam_cm AS REAL
    ) + CAST(
      sd.thigh_cm AS REAL
    ) + CAST(
      sd.knee_cm AS REAL
    ) + CAST(
      sd.hem_cm AS REAL
    )
  ) / 10 AS average_size
FROM
  size_chart sc
INNER JOIN
  brands b ON sc.brand_id = b.brand_id
INNER JOIN
  size_details sd ON sc.chart_id = sd.chart_id
WHERE
  b.brand_name = 'Brand A'
GROUP BY
  sc.chart_id,
  sc.chart_name;
